SELECT access_date, user_id
FROM property_access
WHERE access_date = '2023-05-01';

SELECT AVG(cost) AS average_cost, imprv_type_desc
FROM improvements
GROUP BY imprv_type_desc;

SELECT description, cost
FROM improvements
ORDER BY cost DESC;

SELECT prop_id, MAX(value) AS max_value
FROM property_history
GROUP BY prop_id;

SELECT access_date, access_type, ip_address, device_info
FROM property_access
ORDER BY access_date DESC;
